const input = $json;
const recipient = String(input.recipient ?? '').replace(/\D/g, '');
if (!recipient) {
  throw new Error('recipient is required');
}

const apiKey = String(input.evolution_api_key ?? '').trim();
if (!apiKey) {
  throw new Error('evolution_api_key is required');
}

const baseUrl = String(input.evolution_base_url ?? 'http://192.168.0.115:8081').replace(/\/$/, '');
const instanceName = String(input.evolution_instance_name ?? 'whatsapp').trim();
const caption = String(
  input.caption ?? `Placa ${input.plate ?? 'desconhecida'} detectada`,
).trim();
const hasFrame = Boolean(input.image?.base64);
const endpoint = `${baseUrl}/message/${hasFrame ? 'sendMedia' : 'sendText'}/${instanceName}`;
const body = hasFrame
  ? {
      number: recipient,
      mediatype: 'image',
      mimetype: input.image?.mime_type ?? 'image/jpeg',
      media: input.image.base64,
      caption,
      delay: 0,
      linkPreview: false,
    }
  : {
      number: recipient,
      text: caption,
      delay: 0,
      linkPreview: false,
    };

const evolutionResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: endpoint,
  headers: {
    apikey: apiKey,
  },
  body,
  json: true,
});

return [
  {
    json: {
      ok: true,
      recipient,
      sentAs: hasFrame ? 'media' : 'text',
      endpoint,
      evolutionResponse,
    },
  },
];
